import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Simplest case
  it.todo("empty item list → premium 5 G (only the processing fee)");

  // Base premiums per item type
  it.todo("single sword → premium 105 G (100 base + 5 fee), newcomer first insurance adds 10 → 115");
  it.todo("single amulet → base premium 60 G");
  it.todo("single staff → base premium 80 G");
  it.todo("single potion → base premium 40 G");

  // Components and blocks
  it.todo("2 runes → 50 G base premium");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (one block of 3 + 4 single = 60+100)");
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // Item-specific modifiers (cursed, high enchantment)
  it.todo("cursed sword adds 50% risk surcharge on the item's base premium");
  it.todo("sword enchantment exactly 5 → high-enchantment surcharge applies");
  it.todo("sword enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword enchantment 5 → both surcharges apply");

  // Policy-wide modifiers
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("first insurance carries 10% initial assessment surcharge per item");
  it.todo("second contract gets 15% follow-up discount on policy base premium");

  // Modifier scope examples
  it.todo("cursed sword + plain amulet → 210 G before further modifiers and fee");

  // Integration examples
  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
  it.todo("3-year customer, second quote, cursed sword (steel, ench 7) → 160 G");

  // Rounding
  it.todo("premium yielding 197.5 G → final 198 G (rounded up)");

  // Errors during quote
  it.todo("unknown item type → CLI exits non-zero, error to stderr, no results");

  // Claims — basic
  it.todo("regular sword (ench 3) damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("rune damage 200 → payout 100 (no special clause)");
  it.todo("dragon-material sword ench 8 damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon-material sword ench 9 damage 1000 → payout 400 (50% wins, then deductible)");
  it.todo("dragon-material sword ench 5 damage 800 → payout 700 (full reimburse minus deductible)");
  it.todo("steel sword ench 9 damage 1000 → payout 400");

  // Deductible per damage event
  it.todo("sword (dmg 500) and amulet (dmg 300) → total payout 600 (deductible per item)");

  // Multi-item same type
  it.todo("two swords insured → insurance sum 2000, cap 4000");
  it.todo("two swords both damaged → each treated as separate damage with own deductible");
  it.todo("claim references more items of a type than insured → CLI non-zero exit");

  // Cap behaviour
  it.todo("sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword premium 165 G → cap 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) → insurance sum 1750, premium discount only");
  it.todo("two successive 1500 claims on sword (cap 2000): first 1400 (cap 600), second 600 (cap 0)");

  // Payout rounding
  it.todo("payout yielding 350.5 → final 350 (rounded down)");

  // Claim errors
  it.todo("claim references damage for item not in policy → CLI non-zero exit + stderr");
  it.todo("claim damage amount negative → CLI non-zero exit + stderr");

  // CLI schema example
  it.todo("schema example: amulet quote then fire claim → returns premium and payout/remainingCap");
});

