const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

export const runScenario = (input: Scenario): unknown => {
  const results = input.steps.map(({ items }) => {
    const base = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
    const firstInsurance = base * 0.1;
    return { premium: Math.ceil(base + firstInsurance + PROCESSING_FEE) };
  });
  return { results };
};

