const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const isBlockOfSameType = (items: Item[]): boolean => {
  if (items.length !== BLOCK_SIZE) return false;
  const firstType = items[0].type;
  return items.every((item) => item.type === firstType);
};

const sumOfBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);

const basePremiumFor = (items: Item[]): number =>
  isBlockOfSameType(items) ? BLOCK_PREMIUM : sumOfBasePremiums(items);

const premiumFor = (items: Item[]): number => {
  const basePremium = basePremiumFor(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
};

type QuoteResult = { premium: number };
type ScenarioOutput = { results: QuoteResult[] };

const quoteStep = ({ items }: Step): QuoteResult => ({
  premium: premiumFor(items),
});

export const runScenario = (input: Scenario): ScenarioOutput => ({
  results: input.steps.map(quoteStep),
});

