const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const CURSE_RATE = 0.5;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string; cursed?: boolean };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
type QuoteResult = { premium: number };
type ScenarioOutput = { results: QuoteResult[] };

const groupCountsByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const { type } of items) {
    counts.set(type, (counts.get(type) ?? 0) + 1);
  }
  return counts;
};

const basePremiumForGroup = (type: string, count: number): number => {
  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
  return count * BASE_PREMIUM[type];
};

const basePremiumFor = (items: Item[]): number =>
  Array.from(groupCountsByType(items)).reduce(
    (total, [type, count]) => total + basePremiumForGroup(type, count),
    0,
  );

const curseSurchargeFor = (item: Item): number =>
  item.cursed ? BASE_PREMIUM[item.type] * CURSE_RATE : 0;

const itemSurchargesFor = (items: Item[]): number =>
  items.reduce((sum, item) => sum + curseSurchargeFor(item), 0);

const premiumFor = (items: Item[]): number => {
  const basePremium = basePremiumFor(items);
  const itemSurcharges = itemSurchargesFor(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
  return Math.ceil(
    basePremium + itemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE,
  );
};

const quoteStep = ({ items }: Step): QuoteResult => ({
  premium: premiumFor(items),
});

export const runScenario = (input: Scenario): ScenarioOutput => ({
  results: input.steps.map(quoteStep),
});

