  isFollowUp: boolean,
): QuoteResult => ({
  premium: premiumFor(items, customer, isFollowUp),
});

const insuranceSumFor = (items: Item[]): number =>
  items.reduce((sum, { type }) => sum + INSURANCE_VALUE[type], 0);

const payoutForDamage = ({ amount }: Damage): number =>
  Math.max(0, amount - DEDUCTIBLE);

const claimStep = (
  { policy: policyIndex, incident }: ClaimStep,
  policies: Policy[],
): ClaimResult => {
  const policy = policies[policyIndex];
  const grossPayout = incident.damages.reduce(
    (sum, damage) => sum + payoutForDamage(damage),
    0,
  );
  const payout = Math.min(grossPayout, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
};

export const runScenario = (input: Scenario): ScenarioOutput => {
  const policies: Policy[] = [];
  let quoteCount = 0;
  const results: StepResult[] = input.steps.map((step) => {
    if (step.op === "quote") {
      const isFollowUp = quoteCount > 0;
      quoteCount += 1;
      policies.push({
        items: step.items,
        remainingCap: insuranceSumFor(step.items) * CAP_MULTIPLIER,
      });
      return quoteStep(step, input.customer, isFollowUp);
    }
    return claimStep(step, policies);
  });
  return { results };
};

